// src/app/page.tsx
'use client';

import { signIn, signOut, useSession } from 'next-auth/react';
import { useState } from 'react';
import forge from 'node-forge';

export default function Home() {
  const { data: session, status } = useSession();
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');

  // 인증서 발급 요청 함수
  const handleIssueCert = async () => {
    setLoading(true);
    setMessage('클라이언트에서 RSA 키쌍을 생성 중입니다. 잠시만 기다려주세요...');
    
    // 브라우저가 버벅거리지 않게 setTimeout으로 비동기 처리
    setTimeout(async () => {
      try {
        // 1. 클라이언트(브라우저)에서 RSA 2048비트 키쌍 생성 [cite: 804]
        const keypair = forge.pki.rsa.generateKeyPair(2048);
        const publicKeyPem = forge.pki.publicKeyToPem(keypair.publicKey);
        const privateKeyPem = forge.pki.privateKeyToPem(keypair.privateKey);

        // 2. 생성된 개인키는 브라우저의 localStorage에만 안전하게 저장 [cite: 1308]
        localStorage.setItem('userPrivateKey', privateKeyPem);
        setMessage('키쌍 생성 완료. 서버에 인증서 발급을 요청합니다...');

        // 3. 서버에 공개키를 보내고 인증서 발급 요청 [cite: 805]
        const res = await fetch('/api/cert/issue', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ publicKeyPem }),
        });

        if (!res.ok) throw new Error('인증서 발급 실패');

        const data = await res.json();
        
        // 4. 발급받은 인증서를 localStorage에 저장 [cite: 1310]
        localStorage.setItem('userCert', data.certificate);
        setMessage('인증서가 성공적으로 발급되어 로컬스토리지에 저장되었습니다!');
      } catch (error) {
        console.error(error);
        setMessage('에러가 발생했습니다: ' + (error as Error).message);
      } finally {
        setLoading(false);
      }
    }, 100);
  };

  if (status === 'loading') return <div className="p-8 text-center">로딩 중...</div>;

  return (
    <main className="min-h-screen p-8 max-w-2xl mx-auto font-sans">
      <h1 className="text-3xl font-bold mb-8 text-center">보안 프로토콜 과제 - PKI 실습</h1>

      {!session ? (
        // 비로그인 상태 화면
        <div className="bg-gray-100 p-8 rounded-lg text-center shadow">
          <h2 className="text-xl mb-4">서비스를 이용하려면 로그인이 필요합니다.</h2>
          <button 
            onClick={() => signIn('github')}
            className="bg-gray-900 text-white px-6 py-3 rounded-md hover:bg-gray-800 transition-colors"
          >
            GitHub으로 로그인
          </button>
        </div>
      ) : (
        // 로그인 상태 화면
        <div className="bg-white p-8 rounded-lg shadow-md border border-gray-200">
          <div className="flex items-center justify-between mb-6 pb-6 border-b">
            <div>
              <p className="text-gray-600">환영합니다,</p>
              <h2 className="text-2xl font-semibold text-blue-600">{session.user?.name} 님</h2>
              <p className="text-sm text-gray-500">{session.user?.email}</p>
            </div>
            <button 
              onClick={() => signOut()}
              className="text-sm text-red-500 hover:underline"
            >
              로그아웃
            </button>
          </div>

          <div className="space-y-4">
            <h3 className="text-lg font-medium">인증서 관리</h3>
            <p className="text-sm text-gray-600">
              안전한 통신을 위해 인증서를 발급받으세요. 개인키는 서버로 전송되지 않고 브라우저에만 저장됩니다.
            </p>
            
            <button 
              onClick={handleIssueCert}
              disabled={loading}
              className={`w-full py-3 rounded-md text-white font-medium transition-colors ${
                loading ? 'bg-blue-300 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'
              }`}
            >
              {loading ? '처리 중...' : '인증서 발급받기'}
            </button>

            {message && (
              <div className={`p-4 rounded-md text-sm ${message.includes('에러') ? 'bg-red-50 text-red-700' : 'bg-green-50 text-green-700'}`}>
                {message}
              </div>
            )}
          </div>
        </div>
      )}
    </main>
  );
}